import React, { useEffect, useMemo, useState } from "react";
import EmptyState from "./EmptyState";

export default function DataTable({
  columns,
  data,
  rowKey = "id",
  pageSize = 8,
  loading = false,
  emptyTitle,
  emptyDescription,
  selectable = false,
  selectedRows,
  onSelectedRowsChange,
  bulkActions,
}) {
  const [page, setPage] = useState(1);

  useEffect(() => {
    setPage(1);
  }, [data.length]);

  const totalPages = Math.max(1, Math.ceil(data.length / pageSize));
  const safePage = Math.min(page, totalPages);

  const paginatedData = useMemo(() => {
    const start = (safePage - 1) * pageSize;
    return data.slice(start, start + pageSize);
  }, [data, safePage, pageSize]);

  const selectedIds = selectedRows || [];
  const pageIds = paginatedData.map((row) => row[rowKey]);
  const allPageSelected = pageIds.length > 0 && pageIds.every((id) => selectedIds.includes(id));

  const toggleRow = (id) => {
    if (!onSelectedRowsChange) return;
    if (selectedIds.includes(id)) {
      onSelectedRowsChange(selectedIds.filter((entry) => entry !== id));
      return;
    }
    onSelectedRowsChange([...selectedIds, id]);
  };

  const togglePageSelection = () => {
    if (!onSelectedRowsChange) return;
    if (allPageSelected) {
      onSelectedRowsChange(selectedIds.filter((id) => !pageIds.includes(id)));
      return;
    }
    onSelectedRowsChange([...new Set([...selectedIds, ...pageIds])]);
  };

  if (loading) {
    return (
      <div className="flex h-64 items-center justify-center rounded-3xl border border-white/20 bg-white/40 dark:border-white/5 dark:bg-slate-900/40">
        <div className="flex flex-col items-center gap-3">
          <div className="h-6 w-6 animate-spin rounded-full border-2 border-sky-500 border-t-transparent"></div>
          <p className="text-sm font-semibold tracking-wide text-slate-500 dark:text-slate-400">Loading records...</p>
        </div>
      </div>
    );
  }

  if (!data.length) {
    return <EmptyState title={emptyTitle} description={emptyDescription} />;
  }

  return (
    <div className="overflow-hidden rounded-3xl border border-white/40 bg-white/60 shadow-[0_8px_30px_rgb(0,0,0,0.04)] backdrop-blur-xl dark:border-white/5 dark:bg-slate-900/60 dark:shadow-none transition-colors">
      {selectable && bulkActions?.length && selectedIds.length > 0 ? (
        <div className="flex flex-wrap items-center justify-between gap-2 border-b border-white/20 bg-sky-50/50 px-6 py-3 text-xs font-bold text-sky-700 backdrop-blur-md dark:border-white/10 dark:bg-sky-500/10 dark:text-sky-300">
          <span className="flex items-center gap-2">
            <span className="flex h-5 w-5 items-center justify-center rounded-full bg-sky-500 text-[10px] text-white shadow-sm">{selectedIds.length}</span>
            items selected
          </span>
          <div className="flex gap-2">
            {bulkActions.map((action) => (
              <button
                key={action.label}
                type="button"
                onClick={() => action.onClick(selectedIds)}
                className="rounded-lg border border-sky-200/50 bg-white/80 px-4 py-1.5 text-xs font-bold shadow-sm transition hover:scale-105 active:scale-95 dark:border-sky-500/30 dark:bg-sky-500/20 dark:hover:bg-sky-500/30"
              >
                {action.label}
              </button>
            ))}
          </div>
        </div>
      ) : null}
      <div className="overflow-x-auto">
        <table className="min-w-full border-collapse">
          <thead>
            <tr className="border-b border-white/20 bg-slate-50/50 dark:border-white/5 dark:bg-slate-900/40">
              {selectable ? (
                <th className="w-10 px-6 py-4 text-left">
                  <input type="checkbox" checked={allPageSelected} onChange={togglePageSelection} className="h-4 w-4 rounded border-slate-300 text-sky-500 focus:ring-sky-500 dark:border-slate-600 dark:bg-slate-800 dark:checked:bg-sky-500" />
                </th>
              ) : null}
              {columns.map((column) => (
                <th
                  key={column.key}
                  className="whitespace-nowrap px-6 py-4 text-left text-[11px] font-extrabold uppercase tracking-widest text-slate-500 dark:text-slate-400"
                >
                  {column.header}
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100/50 dark:divide-white/5">
            {paginatedData.map((row) => (
              <tr key={row[rowKey]} className="group transition-all duration-300 hover:bg-white/80 dark:hover:bg-white/5">
                {selectable ? (
                  <td className="px-6 py-4 text-sm text-slate-700 dark:text-slate-200">
                    <input
                      type="checkbox"
                      checked={selectedIds.includes(row[rowKey])}
                      onChange={() => toggleRow(row[rowKey])}
                      className="h-4 w-4 rounded border-slate-300 text-sky-500 focus:ring-sky-500 dark:border-slate-600 dark:bg-slate-800"
                    />
                  </td>
                ) : null}
                {columns.map((column) => (
                  <td key={`${row[rowKey]}-${column.key}`} className="px-6 py-4 text-sm font-medium text-slate-700 dark:text-slate-200 transition-colors group-hover:text-slate-900 dark:group-hover:text-white">
                    {column.render ? column.render(row) : row[column.key]}
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      <div className="flex items-center justify-between border-t border-white/20 bg-slate-50/30 px-6 py-4 text-xs font-semibold text-slate-500 dark:border-white/5 dark:bg-slate-900/20 dark:text-slate-400">
        <span>
          <span className="text-slate-700 dark:text-slate-300">{(safePage - 1) * pageSize + 1}-{Math.min(safePage * pageSize, data.length)}</span> of {data.length}
        </span>
        <div className="flex items-center gap-2">
          <button
            type="button"
            disabled={safePage === 1}
            onClick={() => setPage((value) => Math.max(1, value - 1))}
            className="flex h-8 items-center justify-center rounded-full border border-slate-200 bg-white px-4 font-bold text-slate-600 transition-all hover:bg-slate-50 hover:shadow-sm disabled:cursor-not-allowed disabled:opacity-40 dark:border-white/10 dark:bg-slate-800 dark:text-slate-300 dark:hover:bg-slate-700"
          >
            Prev
          </button>
          <div className="flex h-8 items-center justify-center rounded-full bg-slate-200/50 px-3 py-1 font-bold text-slate-700 dark:bg-slate-800 dark:text-slate-200">
            {safePage} <span className="mx-1 text-slate-400">/</span> {totalPages}
          </div>
          <button
            type="button"
            disabled={safePage === totalPages}
            onClick={() => setPage((value) => Math.min(totalPages, value + 1))}
            className="flex h-8 items-center justify-center rounded-full border border-slate-200 bg-white px-4 font-bold text-slate-600 transition-all hover:bg-slate-50 hover:shadow-sm disabled:cursor-not-allowed disabled:opacity-40 dark:border-white/10 dark:bg-slate-800 dark:text-slate-300 dark:hover:bg-slate-700"
          >
            Next
          </button>
        </div>
      </div>
    </div>
  );
}
